    {
        // ── Validate size ─────────────────────────────────────────────────────
        if (config.Dimensions.Count > 0)
        {
            int effectiveSize = _calculator.CalculateEffectiveSize(config);
            if (effectiveSize > config.MaxMatrixSize)
            {
